103	    .AXI_USER_WIDTH     (TB_AXI_USER_WIDTH)
104	  ) dut (
105	    .clk_i  (clk),
106	    .rst_ni (rst_n),
107	    .slv    (upstream),
108	    .mst    (downstream)
109	  );
110	
111	  typedef logic [TB_AXI_ID_WIDTH-1:0] axi_id_t;
112	
113	  // AXI Master
114	  logic mst_done = 1'b0;
115	  axi_test::axi_rand_master #(
116	    .AW(TB_AXI_ADDR_WIDTH), .DW(TB_AXI_DATA_WIDTH), .IW(TB_AXI_ID_WIDTH), .UW(TB_AXI_USER_WIDTH),
117	    .TA(TB_TA), .TT(TB_TT),
118	    .MAX_READ_TXNS        (TB_AXI_MAX_READ_TXNS),
119	    .MAX_WRITE_TXNS       (TB_AXI_MAX_WRITE_TXNS+2), // master is not required to comply
120	    .AX_MIN_WAIT_CYCLES   (TB_REQ_MIN_WAIT_CYCLES),
121	    .AX_MAX_WAIT_CYCLES   (TB_REQ_MAX_WAIT_CYCLES),
122	    .W_MIN_WAIT_CYCLES    (TB_REQ_MIN_WAIT_CYCLES),
123	    .W_MAX_WAIT_CYCLES    (TB_REQ_MAX_WAIT_CYCLES),
124	    .RESP_MIN_WAIT_CYCLES (TB_RESP_MIN_WAIT_CYCLES),
125	    .RESP_MAX_WAIT_CYCLES (TB_RESP_MAX_WAIT_CYCLES),
126	    .AXI_ATOPS            (1'b1)
127	  ) axi_master = new(upstream_dv);
128	  initial begin
129	    axi_master.reset();
130	    wait(rst_n);
131	    axi_master.add_memory_region({TB_AXI_ADDR_WIDTH{1'b0}}, {TB_AXI_ADDR_WIDTH{1'b1}}, axi_pkg::WTHRU_NOALLOCATE);
132	    axi_master.run(TB_N_TXNS, TB_N_TXNS);
133	    mst_done = 1'b1;
134	  end
135	
136	  initial begin
137	    wait (mst_done);
138	    $finish();
139	  end
140	
141	  // AXI Slave
142	  axi_test::axi_rand_slave #(
143	    .AW(TB_AXI_ADDR_WIDTH), .DW(TB_AXI_DATA_WIDTH), .IW(TB_AXI_ID_WIDTH), .UW(TB_AXI_USER_WIDTH),
144	    .TA(TB_TA), .TT(TB_TT),
145	    .AX_MIN_WAIT_CYCLES   (TB_RESP_MIN_WAIT_CYCLES),
146	    .AX_MAX_WAIT_CYCLES   (TB_RESP_MAX_WAIT_CYCLES),
147	    .R_MIN_WAIT_CYCLES    (TB_RESP_MIN_WAIT_CYCLES),
148	    .R_MAX_WAIT_CYCLES    (TB_RESP_MAX_WAIT_CYCLES),
149	    .RESP_MIN_WAIT_CYCLES (TB_RESP_MIN_WAIT_CYCLES),
150	    .RESP_MAX_WAIT_CYCLES (TB_RESP_MAX_WAIT_CYCLES)
151	  ) axi_slave = new(downstream_dv);
152	  initial begin
153	    axi_slave.reset();
154	    wait (rst_n);
155	    axi_slave.run();
156	  end
157	
158	  typedef struct packed {
159	    axi_id_t  id;
160	    logic     thru;
161	  } w_cmd_t;
162	
163	  typedef axi_test::axi_ax_beat #(
164	    .AW(TB_AXI_ADDR_WIDTH), .IW(TB_AXI_ID_WIDTH), .UW(TB_AXI_USER_WIDTH)
165	  ) ax_beat_t;
166	  typedef axi_test::axi_b_beat #(
167	    .IW(TB_AXI_ID_WIDTH), .UW(TB_AXI_USER_WIDTH)
168	  ) b_beat_t;
169	  typedef axi_test::axi_r_beat #(
170	    .DW(TB_AXI_DATA_WIDTH), .IW(TB_AXI_ID_WIDTH), .UW(TB_AXI_USER_WIDTH)
171	  ) r_beat_t;
172	  typedef axi_test::axi_w_beat #(
173	    .DW(TB_AXI_DATA_WIDTH), .UW(TB_AXI_USER_WIDTH)
174	  ) w_beat_t;
175	
176	  // Put W beats into transfer queue or drop them and inject B responses based on W command.
177	  function automatic void process_w_beat(w_beat_t w_beat, ref w_cmd_t w_cmd_queue[$],
178	      ref w_beat_t w_xfer_queue[$], ref b_beat_t b_inject_queue[$]
179	  );
180	    w_cmd_t w_cmd = w_cmd_queue[0];
181	    if (w_cmd.thru) begin
182	      w_xfer_queue.push_back(w_beat);
183	    end
184	    if (w_beat.w_last) begin
185	      if (!w_cmd.thru) begin
186	        automatic b_beat_t b_beat = new;
187	        b_beat.b_id = w_cmd.id;
188	        b_beat.b_resp = RESP_SLVERR;
189	        b_inject_queue.push_back(b_beat);
190	      end
191	      void'(w_cmd_queue.pop_front());
192	    end
193	  endfunction
194	
195	  // Monitor and check responses of filter.
196	  initial begin
197	    static ax_beat_t  ar_xfer_queue[$],
198	                      aw_xfer_queue[$];
199	    static b_beat_t   b_inject_queue[$],
200	                      b_xfer_queue[$];
201	    static r_beat_t   r_inject_queue[$],
202	                      r_xfer_queue[$];
203	    static w_cmd_t    w_cmd_queue[$];
204	    static w_beat_t   w_act_queue[$],
205	                      w_undecided_queue[$],
206	                      w_xfer_queue[$];
207	    forever begin
208	      @(posedge clk);
209	      #(TB_TT);
210	      // Ensure that downstream never sees an `aw_atop`.
211	      if (downstream.aw_valid) begin
212	        assert (downstream.aw_atop == '0);
213	      end
214	      // Push upstream ARs into transfer queues.
215	      if (upstream.ar_valid && upstream.ar_ready) begin
216	        automatic ax_beat_t ar_beat = new;
217	        ar_beat.ax_id     = upstream.ar_id;
218	        ar_beat.ax_addr   = upstream.ar_addr;
219	        ar_beat.ax_len    = upstream.ar_len;
220	        ar_beat.ax_size   = upstream.ar_size;
221	        ar_beat.ax_burst  = upstream.ar_burst;
222	        ar_beat.ax_lock   = upstream.ar_lock;
223	        ar_beat.ax_cache  = upstream.ar_cache;
224	        ar_beat.ax_prot   = upstream.ar_prot;
225	        ar_beat.ax_qos    = upstream.ar_qos;
226	        ar_beat.ax_region = upstream.ar_region;
227	        ar_beat.ax_user   = upstream.ar_user;
228	        ar_xfer_queue.push_back(ar_beat);
229	      end
230	      // Push upstream AWs that must go through into transfer queues, and push to W command queue.
231	      if (upstream.aw_valid && upstream.aw_ready) begin
232	        automatic ax_beat_t aw_beat = new;
233	        automatic w_cmd_t w_cmd;
234	        aw_beat.ax_id     = upstream.aw_id;
235	        aw_beat.ax_addr   = upstream.aw_addr;
236	        aw_beat.ax_len    = upstream.aw_len;
237	        aw_beat.ax_size   = upstream.aw_size;
238	        aw_beat.ax_burst  = upstream.aw_burst;
239	        aw_beat.ax_lock   = upstream.aw_lock;
240	        aw_beat.ax_cache  = upstream.aw_cache;
241	        aw_beat.ax_prot   = upstream.aw_prot;
242	        aw_beat.ax_qos    = upstream.aw_qos;
243	        aw_beat.ax_region = upstream.aw_region;
244	        aw_beat.ax_atop   = upstream.aw_atop;
245	        aw_beat.ax_user   = upstream.aw_user;
246	        w_cmd.id = aw_beat.ax_id;
247	        w_cmd.thru = (aw_beat.ax_atop == '0);
248	        w_cmd_queue.push_back(w_cmd);
249	        if (w_cmd.thru) begin
250	          aw_xfer_queue.push_back(aw_beat);
251	        end else if (aw_beat.ax_atop[5:4] != ATOP_ATOMICSTORE) begin
252	          for (int unsigned i = 0; i < aw_beat.ax_len + 1; i++) begin
253	            automatic r_beat_t r_beat = new;
254	            r_beat.r_id = aw_beat.ax_id;
255	            r_beat.r_resp = RESP_SLVERR;
256	            r_beat.r_data = '0;
257	            r_beat.r_user = '0;
258	            r_beat.r_last = (i == aw_beat.ax_len);
259	            r_inject_queue.push_back(r_beat);
260	          end
261	        end
262	      end
263	      // Handle undecided upstream W beats if possible.
264	      while (w_undecided_queue.size() > 0 && w_cmd_queue.size() > 0) begin
265	        automatic w_beat_t w_beat = w_undecided_queue.pop_front();
266	        process_w_beat(w_beat, w_cmd_queue, w_xfer_queue, b_inject_queue);
267	      end
268	      // Process upstream W beats or put them into queue of undecided W beats.
269	      if (upstream.w_valid && upstream.w_ready) begin
270	        automatic w_beat_t w_beat = new;
271	        w_beat.w_data = upstream.w_data;
272	        w_beat.w_strb = upstream.w_strb;
273	        w_beat.w_last = upstream.w_last;
274	        w_beat.w_user = upstream.w_user;
275	        if (w_cmd_queue.size() > 0) begin
276	          process_w_beat(w_beat, w_cmd_queue, w_xfer_queue, b_inject_queue);
277	        end else begin
278	          w_undecided_queue.push_back(w_beat);
279	        end
280	      end
281	      // Push downstream Rs into transfer queue.
282	      if (downstream.r_valid && downstream.r_ready) begin
283	        automatic r_beat_t r_beat = new;
284	        r_beat.r_id   = downstream.r_id;
285	        r_beat.r_data = downstream.r_data;
286	        r_beat.r_resp = downstream.r_resp;
287	        r_beat.r_last = downstream.r_last;
288	        r_beat.r_user = downstream.r_user;
289	        r_xfer_queue.push_back(r_beat);
290	      end
291	      // Push downstream Bs into transfer queue.
292	      if (downstream.b_valid && downstream.b_ready) begin
293	        automatic b_beat_t b_beat = new;
294	        b_beat.b_id   = downstream.b_id;
295	        b_beat.b_resp = downstream.b_resp;
296	        b_beat.b_user = downstream.b_user;
297	        b_xfer_queue.push_back(b_beat);
298	      end
299	      // Ensure downstream ARs match beats from transfer queue.
300	      if (downstream.ar_valid && downstream.ar_ready) begin
301	        automatic ax_beat_t exp_beat;
302	        assert (ar_xfer_queue.size() > 0) else $fatal(1, "downstream.AR: Unknown beat!");
303	        exp_beat = ar_xfer_queue.pop_front();
304	        assert (downstream.ar_id      == exp_beat.ax_id);
305	        assert (downstream.ar_addr    == exp_beat.ax_addr);
306	        assert (downstream.ar_len     == exp_beat.ax_len);
307	        assert (downstream.ar_size    == exp_beat.ax_size);
308	        assert (downstream.ar_burst   == exp_beat.ax_burst);
309	        assert (downstream.ar_cache   == exp_beat.ax_cache);
310	        assert (downstream.ar_prot    == exp_beat.ax_prot);
311	        assert (downstream.ar_qos     == exp_beat.ax_qos);
312	        assert (downstream.ar_region  == exp_beat.ax_region);
313	        assert (downstream.ar_user    == exp_beat.ax_user);
314	      end
315	      // Ensure downstream AWs match beats from transfer queue.
316	      if (downstream.aw_valid && downstream.aw_ready) begin
317	        automatic ax_beat_t exp_beat;
318	        assert (aw_xfer_queue.size() > 0) else $fatal(1, "downstream.AW: Unknown beat!");
319	        exp_beat = aw_xfer_queue.pop_front();
320	        assert (downstream.aw_id      == exp_beat.ax_id);
321	        assert (downstream.aw_addr    == exp_beat.ax_addr);
322	        assert (downstream.aw_len     == exp_beat.ax_len);
323	        assert (downstream.aw_size    == exp_beat.ax_size);
324	        assert (downstream.aw_burst   == exp_beat.ax_burst);
325	        assert (downstream.aw_cache   == exp_beat.ax_cache);
326	        assert (downstream.aw_prot    == exp_beat.ax_prot);
327	        assert (downstream.aw_qos     == exp_beat.ax_qos);
328	        assert (downstream.aw_region  == exp_beat.ax_region);
329	        assert (downstream.aw_user    == exp_beat.ax_user);
330	      end
331	      // Ensure downstream Ws match beats from transfer queue.
332	      while (w_act_queue.size() > 0 && w_xfer_queue.size() > 0) begin
333	        automatic w_beat_t exp_beat = w_xfer_queue.pop_front();
334	        automatic w_beat_t act_beat = w_act_queue.pop_front();
335	        assert (act_beat.w_data == exp_beat.w_data);
336	        assert (act_beat.w_strb == exp_beat.w_strb);
337	        assert (act_beat.w_last == exp_beat.w_last);
338	        assert (act_beat.w_user == exp_beat.w_user);
339	      end
340	      if (downstream.w_valid && downstream.w_ready) begin
341	        if (w_xfer_queue.size() > 0) begin
342	          automatic w_beat_t exp_beat = w_xfer_queue.pop_front();
343	          assert (downstream.w_data == exp_beat.w_data);
344	          assert (downstream.w_strb == exp_beat.w_strb);
345	          assert (downstream.w_last == exp_beat.w_last);
346	          assert (downstream.w_user == exp_beat.w_user);
347	        end else begin
348	          automatic w_beat_t act_beat = new;
349	          act_beat.w_data = downstream.w_data;
350	          act_beat.w_strb = downstream.w_strb;
351	          act_beat.w_last = downstream.w_last;
352	          act_beat.w_user = downstream.w_user;
353	          w_act_queue.push_back(act_beat);
354	        end
355	      end
356	      // Ensure upstream Rs match beats from transfer or inject queue.
357	      if (upstream.r_valid && upstream.r_ready) begin
358	        automatic r_beat_t exp_beat;
359	        if (r_inject_queue.size() > 0 && r_inject_queue[0].r_id == upstream.r_id) begin
360	          exp_beat = r_inject_queue.pop_front();
361	        end else if (r_xfer_queue.size() > 0 && r_xfer_queue[0].r_id == upstream.r_id) begin
362	          exp_beat = r_xfer_queue.pop_front();
363	        end else begin
364	          $fatal(1, "upstream.R: Unknown beat!");
365	        end
366	        assert (upstream.r_id   == exp_beat.r_id);
367	        assert (upstream.r_data == exp_beat.r_data);
368	        assert (upstream.r_resp == exp_beat.r_resp);
369	        assert (upstream.r_last == exp_beat.r_last);
370	        assert (upstream.r_user == exp_beat.r_user);
371	      end
372	      // Ensure upstream Bs match beats from transfer or inject queue.
373	      if (upstream.b_valid && upstream.b_ready) begin
374	        automatic b_beat_t exp_beat;
375	        if (b_inject_queue.size() > 0 && b_inject_queue[0].b_id == upstream.b_id) begin
376	          exp_beat = b_inject_queue.pop_front();
377	        end else if (b_xfer_queue.size() > 0 && b_xfer_queue[0].b_id == upstream.b_id) begin
378	          exp_beat = b_xfer_queue.pop_front();
379	        end else begin
380	          $fatal(1, "upstream.B: Unknown beat!");
381	        end
382	        assert (upstream.b_id   == exp_beat.b_id);
383	        assert (upstream.b_resp == exp_beat.b_resp);
384	        assert (upstream.b_user == exp_beat.b_user);
385	      end
386	    end
387	  end
388	
389	endmodule
